-u_{t_z} & -u_{y_t} & u_{t_y} & u_{x_t} & -u_{t_x} & 0 & u_\tau \\[1mm]
u_{z_t} & -u_{t_y} & -u_{y_t} & u_{t_x} & u_{x_t} & -u_\tau & 0 \\[1mm]
