\subsubsection*{Metric:}
The bodyhole manifold in 7-d is flat. This is the only way to satisfy invariance requirements in lower projected 4-d Minkowski space. Define metric:

\begin{flalign*}
g_{IO}&=\delta_{IO}&&\\
ds^2&=g_{IO}dx^Idx^O&&\\
&= d\tau^2+ dx_t^2 + dt_x^2 + dy_t^2 + dt_y^2 + dz_t^2 + dt_z^2\\
&= d\tau^2+ \sum_i(di_t^2 + dt_i^2)
\end{flalign*}


\subsubsection*{Dot Product:}
\begin{flalign*}
W &= U \cdot V&&\\
&=u_\tau v_\tau (\hat \tau \cdot \hat \tau) +u_{x_t} v_{x_t} (\hat x_t \cdot \hat x_t) + u_{t_x} v_{t_x} (\hat t_x \cdot \hat t_x) + u_{y_t} v_{y_t} (\hat y_t \cdot \hat y_t) + u_{t_y} v_{t_y} (\hat t_y \cdot \hat t_y) + u_{z_t} v_{z_t} (\hat z_t \cdot \hat z_t) + u_{t_z} v_{t_z} (\hat t_z \cdot \hat t_z)\\
